/**
 * Area Browser Component
 * Lists areas and allows loading/creating/deleting them
 */

import React, { useState } from 'react';
import useWorldBuilderStore from '../store/store.js';

function AreaBrowser() {
  const [showNewArea, setShowNewArea] = useState(false);
  const [newAreaName, setNewAreaName] = useState('');
  const { areas, currentArea, loadArea, createArea, deleteArea, loading } =
    useWorldBuilderStore();

  const handleCreateArea = async (e) => {
    e.preventDefault();
    if (newAreaName.trim()) {
      await createArea(newAreaName, {
        author: 'Builder',
        levelRange: '1-50',
        vnumRange: [1000, 1999],
      });
      setNewAreaName('');
      setShowNewArea(false);
    }
  };

  const handleLoadArea = (areaName) => {
    loadArea(areaName);
  };

  const handleDeleteArea = (areaName) => {
    if (window.confirm(`Delete ${areaName}? This cannot be undone.`)) {
      deleteArea(areaName);
    }
  };

  return (
    <div className="area-browser">
      <h2>📁 Areas</h2>
      
      <button onClick={() => setShowNewArea(!showNewArea)} className="mt-2 mb-2">
        {showNewArea ? '✕ Cancel' : '+ New Area'}
      </button>

      {showNewArea && (
        <form onSubmit={handleCreateArea} className="card mb-2">
          <input
            type="text"
            placeholder="Area name (e.g., dragon_lair)"
            value={newAreaName}
            onChange={(e) => setNewAreaName(e.target.value)}
            className="mb-2"
            disabled={loading}
          />
          <button type="submit" disabled={loading || !newAreaName.trim()}>
            {loading ? 'Creating...' : 'Create'}
          </button>
        </form>
      )}

      {areas.length === 0 ? (
        <p className="text-muted mt-2">No areas found. Create one to get started!</p>
      ) : (
        <div className="areas-list mt-2">
          {areas.map((area) => (
            <div
              key={area.name}
              className={`area-item card ${currentArea === area.name ? 'active' : ''}`}
            >
              <div className="area-header">
                <strong>{area.name}</strong>
              </div>
              <p className="text-muted" style={{ fontSize: '12px', margin: '4px 0' }}>
                {Math.round(area.size / 1024)} KB
              </p>
              <div className="area-actions" style={{ display: 'flex', gap: '8px', marginTop: '8px' }}>
                <button
                  onClick={() => handleLoadArea(area.name)}
                  disabled={loading}
                  style={{ flex: 1 }}
                >
                  {currentArea === area.name ? '✓ Loaded' : 'Load'}
                </button>
                <button
                  onClick={() => handleDeleteArea(area.name)}
                  disabled={loading}
                  className="danger"
                  style={{ flex: 1 }}
                >
                  Delete
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      <style>{`
        .area-browser {
          display: flex;
          flex-direction: column;
        }

        .area-browser h2 {
          font-size: 18px;
          margin-bottom: 16px;
        }

        .areas-list {
          display: flex;
          flex-direction: column;
          gap: 8px;
        }

        .area-item {
          cursor: pointer;
          transition: all 0.2s;
          border-left: 4px solid #ddd;
        }

        .area-item:hover {
          background: #f9f9f9;
          border-left-color: #667eea;
        }

        .area-item.active {
          background: #f0f4ff;
          border-left-color: #667eea;
          font-weight: bold;
        }

        .area-header {
          margin-bottom: 4px;
        }

        .area-actions {
          margin-top: 8px;
        }
      `}</style>
    </div>
  );
}

export default AreaBrowser;
